import type { Plugin } from 'vite'

export function restartOnAddUnlink(): Plugin {
  return {
    name: 'restart-on-add-unlink',
    configureServer(server) {
      server.watcher.add('./app/**')
      server.watcher.on('add', async () => {
        await server.restart()
      })
      server.watcher.on('unlink', async () => {
        await server.restart()
      })
    },
  }
}

const createUpgradeRequest = (request: IncomingMessage): Request => {
  const protocol = (request.socket as { encrypted?: boolean }).encrypted ? 'https' : 'http'
  const url = new URL(request.url ?? '/', `${protocol}://${request.headers.host ?? 'localhost'}`)
  const headers = new Headers()
  for (const key in request.headers) {
    const value = request.headers[key]
    if (!value) {
      continue
    }
    headers.append(key, Array.isArray(value) ? value[0] : value)
  }
  return new Request(url, {
    headers,
  })
}

async function validateBearerToken(
  req: Request,
): Promise<{ userId: string; token: string } | null> {
  const authHeader = req.headers.get("authorization");
  if (!authHeader) return null;
  const match = authHeader.match(/^Bearer\s+(\S+)$/i);
  if (!match?.[1]) return null;
  const token = match[1];

  const headers = new Headers();
  headers.set("authorization", `Bearer ${token}`);
  const session = await auth.api.getSession({ headers });

  if (!session?.user?.id) return null;
  return { userId: session.user.id, token };
}

