origin: (origin, c) => {
  const allowed = (c.env as any)?.CORS_ORIGINS as string | undefined
  if (!allowed) return null // No env var = reject cross-origin (secure default)
  const list = allowed.split(',').map((s: string) => s.trim())
  return list.includes(origin) ? origin : null
}

function pipeTextStream(c: Context, run: (cfg: LLMRequestConfig) => ReturnType<typeof streamText>) {
  return legacySSE(c, async (emit) => {
    const result = run(llmConfigFrom(c))
    for await (const delta of result.textStream)
      await emit.send(delta)
    await emit.done()
  })
}

import type { MiddlewareHandler } from 'hono'
import { createMiddleware } from 'hono/factory'

export const hello = (message: string = 'Hello!'): MiddlewareHandler => {
  return createMiddleware(async (c, next) => {
    await next()
    c.res.headers.append('X-Message', message)
  })
}

function addTimingMeta(c: any, meta: any = {}, executionStartTime?: number) {
  const totalTime = Date.now() - c.get('startTime')
  const executionTime = executionStartTime ? Date.now() - executionStartTime : undefined

  return {
    ...meta,
    timing: {
      total: totalTime,
      execution: executionTime,
      unit: 'ms'
    }
  }
}

function addConnection(
  projectId: string,
  ws: WSContext,
  userId: string,
  initiatorId: string,
) {
  if (!projectConnections.has(projectId)) {
    projectConnections.set(projectId, new Set());
  }
  const conn: ProjectConnection = { ws, userId, initiatorId };
  projectConnections.get(projectId)?.add(conn);
  return conn;
}

// Avoid character classes in glob patterns for rolldown-vite compatibility
// ref: https://github.com/rolldown/rolldown/issues/4973
export const filterByPattern = <T>(
  files: Record<string, T>,
  patterns: RegExp[]
): Record<string, T> => {
  return Object.fromEntries(
    Object.entries(files).filter(([path]) => patterns.some((pattern) => pattern.test(path)))
  )
}

Object.defineProperty(Response, 'redirect', {
  value: function redirect(url: string | URL, status = 302): Response {
    if (!validRedirectStatuses.has(status)) {
      throw new RangeError('Invalid status code')
    }
    return new Response(null, {
      status,
      headers: { location: parseRedirectUrl(url) },
    })
  },
  writable: true,
  configurable: true,
})

const handleResponseError = (e: unknown, outgoing: ServerResponse | Http2ServerResponse) => {
  const err = (e instanceof Error ? e : new Error('unknown error', { cause: e })) as Error & {
    code: string
  }
  if (err.code === 'ERR_STREAM_PREMATURE_CLOSE') {
    console.info('The user aborted a request.')
  } else {
    console.error(e)
    if (!outgoing.headersSent) {
      outgoing.writeHead(500, { 'Content-Type': 'text/plain' })
    }
    outgoing.end(`Error: ${err.message}`)
    outgoing.destroy(err)
  }
}

export const nodeAdapter = (): Adapter => {
  if (typeof globalThis.navigator === 'undefined') {
    // @ts-expect-error not typed well
    globalThis.navigator = {
      userAgent: 'Node.js',
    }
  } else {
    Object.defineProperty(globalThis.navigator, 'userAgent', {
      value: 'Node.js',
      writable: false,
    })
  }
  return {
    env: process.env,
  }
}
